use serde::{Deserialize,Serialize};
use std::{env,fs,io::{Read,Write},os::unix::net::{UnixListener,UnixStream},process::{Command,Stdio},thread};
#[derive(Serialize,Deserialize)]struct Action{tool:String,arg:String,why:String}
fn sh(cmd:&str,stdin:&str)->Option<String>{let mut c=Command::new("/bin/sh");let mut ch=c.arg("-c").arg(cmd).stdin(Stdio::piped()).stdout(Stdio::piped()).stderr(Stdio::null()).spawn().ok()?;ch.stdin.take()?.write_all(stdin.as_bytes()).ok()?;let o=ch.wait_with_output().ok()?;if o.status.success(){Some(String::from_utf8_lossy(&o.stdout).to_string())}else{None}}
fn decide(state:&str)->Vec<Action>{if let Ok(cmd)=env::var("CORTEX_CACTUS_CMD"){if let Some(out)=sh(&cmd,state){if let Ok(v)=serde_json::from_str::<Vec<Action>>(&out){return v}}return vec![Action{tool:"verify".into(),arg:"true".into(),why:"modeld-cactus-error-fallback".into()}]}let _=serde_json::from_str::<serde_json::Value>(state);vec![Action{tool:"verify".into(),arg:"true".into(),why:"modeld-heartbeat".into()}]}
fn handle(mut s:UnixStream){let mut buf=String::new();let _=s.read_to_string(&mut buf);let out=serde_json::to_string(&decide(&buf)).unwrap_or_else(|_|"[]".into());let _=s.write_all(out.as_bytes());}
fn main(){let sock=env::var("CORTEX_MODEL_SOCK").unwrap_or_else(|_|"/run/cortex-model.sock".into());let _=fs::remove_file(&sock);if let Some(p)=std::path::Path::new(&sock).parent(){let _=fs::create_dir_all(p);}let l=UnixListener::bind(&sock).unwrap_or_else(|e|panic!("bind {}: {}",sock,e));for c in l.incoming(){match c{Ok(s)=>{thread::spawn(||handle(s));},Err(_)=>break}}}
